 22→/**
 23→ * TM002 員工假別明細查詢 Processor
 24→ * <p>
 25→ * 依員工ID+年度查詢假別明細
 26→ * API 路徑：POST /api/tm002EmpVacationDetail
 27→ *
 28→ * @author SoeTek Team
 29→ * @since 2026-03-26
 30→ */
 31→@Slf4j
 32→@ApplicationScoped
 33→@Named("tm002EmpVacationDetailProcessor")
 34→@RegisterForReflection
 35→public class Tm002EmpVacationDetailProcessor extends ApiRouteProcessor {
 36→
 37→    @Inject
 38→    Tm002EmpVacationService empVacationService;
 39→
 40→    @Override
 41→    public Map<String, Object> getTemplateParams() {
 42→        return Map.of(
 43→                "routeId", "tm002EmpVacationDetail",
 44→                "apiDescription", "查詢員工假別明細",
 45→                "requiredFields", "empId,year");
 46→    }
 47→
 48→    @Override
 49→    protected String getProcessorType() {
 50→        return LogType.API_PROCESSING;
 51→    }
 52→
 53→    @Override
 54→    @ActivateRequestContext
 55→    @AuditLog(
 56→            operation = AuditLog.OperationType.QUERY,
 57→            entity = "TmEmpVacation",
 58→            description = "查詢員工假別明細",
 59→            logParameters = true,
 60→            logResult = true
 61→    )
 62→    public Object process(Exchange exchange, @Body Map<String, Object> payload,
 63→                          @Headers Map<String, Object> headers) throws Exception {
 64→        return executeWithErrorHandling(exchange, payload, headers);
 65→    }
 66→
 67→    @Override
 68→    protected Object processBusinessLogic(
 69→            Exchange exchange,
 70→            Map<String, Object> payload,
 71→            Map<String, Object> headers,
 72→            String traceId,
 73→            String routeId) throws Exception {
 74→
 75→        Integer empId = getRequiredInteger(payload, "empId", "員工ID");
 76→        Integer year = getRequiredInteger(payload, "year", "年度");
 77→
 78→        log.debug("[TM002 明細查詢] empId: {}, year: {}, TraceId: {}", empId, year, traceId);
 79→
 80→        List<Map<String, Object>> records = empVacationService.queryEmpVacationDetail(empId, year);
 81→
 82→        log.info("[TM002 明細查詢] 完成 - 回傳 {} 筆, TraceId: {}", records.size(), traceId);
 83→
 84→        Map<String, Object> data = new HashMap<>();
 85→        data.put("records", records);
 86→
 87→        Map<String, Object> response = new HashMap<>();
 88→        response.put("success", true);
 89→        response.put("message", "查詢成功");
 90→        response.put("data", data);
 91→        response.put("traceId", traceId);
 92→        return response;
 93→    }
 94→
 95→    private Integer getRequiredInteger(Map<String, Object> data, String key, String fieldName) {
 96→        Object value = data.get(key);
 97→        if (value == null) {
 98→            throw new BusinessException("REQUIRED_FIELD", 400, fieldName + " 為必填欄位");
 99→        }
100→        if (value instanceof Number) {
101→            return ((Number) value).intValue();
102→        }
103→        try {
104→            return Integer.parseInt(value.toString().trim());
105→        } catch (NumberFormatException e) {
106→            throw new BusinessException("INVALID_FORMAT", 400, fieldName + " 格式錯誤，必須為整數");
107→        }
108→    }
109→}
