 90→
 91→        List<Map<String, Object>> savedRecords = empVacationService.saveEmpVacationDetails(empId, details);
 92→
 93→        log.info("[TM002 儲存] 完成 - 儲存 {} 筆, TraceId: {}", savedRecords.size(), traceId);
 94→
 95→        Map<String, Object> data = new HashMap<>();
 96→        data.put("records", savedRecords);
 97→        data.put("entityId", empId);
 98→
 99→        Map<String, Object> response = new HashMap<>();
100→        response.put("success", true);
101→        response.put("message", "儲存成功");
102→        response.put("data", data);
103→        response.put("traceId", traceId);
104→        return response;
105→    }
106→}
