  1→/**
  2→ * TM002 員工年度假別額度維護 - Store
  3→ *
  4→ * @author SoeTek Team
  5→ * @since 2026-03-26
  6→ */
  7→
  8→import { defineStore } from 'pinia'
  9→import { ref, computed } from 'vue'
 10→import { tm002Service } from 'src/services/tm/tm002Service'
 11→import type {
 12→  IEmpVacationListItem,
 13→  IEmpVacationQueryParams,
 14→  IEmpVacationDetail,
 15→  IDefaultVacationItem,
 16→  IEmployeeInfo,
 17→  IBatchValidateResult,
 18→  IEmpVacationSaveParams,
 19→  IBatchImportParams
 20→} from 'src/types/tm/tm002'
 21→
 22→export const useTm002Store = defineStore('tm002', () => {
 23→
 24→  // ==================== State ====================
 25→
 26→  const records = ref<IEmpVacationListItem[]>([])
 27→  const totalCount = ref(0)
 28→  const currentPage = ref(1)
 29→  const queryLoading = ref(false)
 30→  const saveLoading = ref(false)
 31→  const deleteLoading = ref(false)
 32→
 33→  // Dialog state
 34→  const detailRecords = ref<IEmpVacationDetail[]>([])
 35→  const defaultVacationItems = ref<IDefaultVacationItem[]>([])
 36→  const employeeInfo = ref<IEmployeeInfo | null>(null)
 37→  const batchValidateResults = ref<IBatchValidateResult[]>([])
 38→
 39→  // ==================== Getters ====================
 40→
 41→  const hasData = computed(() => records.value.length > 0)
 42→  const isAnyLoading = computed(() =>
 43→    queryLoading.value || saveLoading.value || deleteLoading.value
 44→  )
 45→
 46→  // ==================== Actions ====================
 47→
 48→  /** 清單查詢 */
 49→  async function query(params?: IEmpVacationQueryParams): Promise<boolean> {
 50→    queryLoading.value = true
 51→    try {
 52→      const response = await tm002Service.query(params)
 53→      if (response.success && response.data) {
 54→        records.value = response.data.records || []
 55→        totalCount.value = response.data.totalCount || 0
 56→        currentPage.value = response.data.currentPage || 1
 57→        return true
 58→      }
 59→      return false
 60→    } catch (err: unknown) {
 61→      console.error('[TM002] 查詢失敗', err)
 62→      return false
 63→    } finally {
 64→      queryLoading.value = false
 65→    }
 66→  }
 67→
 68→  /** 員工資訊查詢 */
 69→  async function queryEmpInfo(empAccount: string): Promise<IEmployeeInfo | null> {
 70→    try {
 71→      const response = await tm002Service.queryEmpInfo(empAccount)
 72→      if (response.success && response.data) {
 73→        employeeInfo.value = response.data
 74→        return response.data
 75→      }
 76→      return null
 77→    } catch (err: unknown) {
 78→      console.error('[TM002] 員工查詢失敗', err)
 79→      return null
 80→    }
 81→  }
 82→
 83→  /** 執行預設（病假載入） */
 84→  async function loadDefaultVacation(year: number): Promise<boolean> {
 85→    try {
 86→      const response = await tm002Service.getDefaultVacation(year)
 87→      if (response.success && response.data) {
 88→        defaultVacationItems.value = response.data.records || []
 89→        return true
 90→      }
 91→      return false
 92→    } catch (err: unknown) {
 93→      console.error('[TM002] 執行預設失敗', err)
 94→      return false
 95→    }
 96→  }
 97→
 98→  /** 明細查詢 */
 99→  async function queryDetail(empId: number, year: number): Promise<boolean> {
100→    queryLoading.value = true
101→    try {
102→      const response = await tm002Service.queryDetail(empId, year)
103→      if (response.success && response.data) {
104→        detailRecords.value = response.data.records || []
105→        return true
106→      }
107→      return false
108→    } catch (err: unknown) {
109→      console.error('[TM002] 明細查詢失敗', err)
110→      return false
111→    } finally {
112→      queryLoading.value = false
113→    }
114→  }
115→
116→  /** 儲存明細 */
117→  async function saveDetails(params: IEmpVacationSaveParams): Promise<boolean> {
118→    saveLoading.value = true
119→    try {
120→      const response = await tm002Service.save(params)
121→      if (response.success) {
122→        return true
123→      }
124→      return false
125→    } catch (err: unknown) {
126→      console.error('[TM002] 儲存失敗', err)
127→      throw err
128→    } finally {
129→      saveLoading.value = false
130→    }
131→  }
132→
133→  /** 刪除明細 */
134→  async function deleteDetail(empVacationId: number): Promise<boolean> {
135→    deleteLoading.value = true
136→    try {
137→      const response = await tm002Service.deleteDetail(empVacationId)
138→      if (response.success) {
139→        return true
140→      }
141→      return false
142→    } catch (err: unknown) {
143→      console.error('[TM002] 刪除失敗', err)
144→      throw err
145→    } finally {
146→      deleteLoading.value = false
147→    }
148→  }
149→
150→  /** 批次驗證 */
151→  async function batchValidate(empAccounts: string[]): Promise<boolean> {
152→    try {
153→      const response = await tm002Service.batchValidate(empAccounts)
154→      if (response.success && response.data) {
155→        batchValidateResults.value = response.data.results || []
156→        return true
157→      }
158→      return false
159→    } catch (err: unknown) {
160→      console.error('[TM002] 批次驗證失敗', err)
161→      return false
162→    }
163→  }
164→
165→  /** 批次匯入 */
166→  async function batchImport(params: IBatchImportParams): Promise<number> {
167→    saveLoading.value = true
168→    try {
169→      const response = await tm002Service.batchImport(params)
170→      if (response.success && response.data) {
171→        return response.data.createdCount
172→      }
173→      return 0
174→    } catch (err: unknown) {
175→      console.error('[TM002] 批次匯入失敗', err)
176→      throw err
177→    } finally {
178→      saveLoading.value = false
179→    }
180→  }
181→
182→  /** 重置 */
183→  function $reset() {
184→    records.value = []
185→    totalCount.value = 0
186→    currentPage.value = 1
187→    queryLoading.value = false
188→    saveLoading.value = false
189→    deleteLoading.value = false
190→    detailRecords.value = []
191→    defaultVacationItems.value = []
192→    employeeInfo.value = null
193→    batchValidateResults.value = []
194→  }
195→
196→  // ==================== Return ====================
197→
198→  return {
199→    // State
200→    records, totalCount, currentPage,
201→    queryLoading, saveLoading, deleteLoading,
202→    detailRecords, defaultVacationItems, employeeInfo, batchValidateResults,
203→    // Getters
204→    hasData, isAnyLoading,
205→    // Actions
206→    query, queryEmpInfo, loadDefaultVacation, queryDetail,
207→    saveDetails, deleteDetail, batchValidate, batchImport, $reset
208→  }
209→})
