  1→package org.soetek.eap.tm.service;
  2→
  3→import io.quarkus.hibernate.orm.PersistenceUnit;
  4→import jakarta.enterprise.context.ApplicationScoped;
  5→import jakarta.inject.Inject;
  6→import jakarta.persistence.EntityManager;
  7→import jakarta.persistence.Query;
  8→import jakarta.transaction.Transactional;
  9→import lombok.extern.slf4j.Slf4j;
 10→import org.soetek.eap.tm.domain.TmEmpVacationEntity;
 11→import org.soetek.foundation.exception.BusinessException;
 12→import org.soetek.foundation.util.DateFormatUtil;
 13→
 14→import java.math.BigDecimal;
 15→import java.time.LocalDate;
 16→import java.time.LocalDateTime;
 17→import java.util.ArrayList;
 18→import java.util.HashMap;
 19→import java.util.List;
 20→import java.util.Map;
 21→
 22→/**
 23→ * TM002 員工年度假別額度維護服務
 24→ * <p>
 25→ * 提供執行預設、明細查詢、儲存、刪除、批次驗證、批次匯入等功能。
 26→ *
 27→ * @author SoeTek Team
 28→ * @since 2026-03-26
 29→ */
 30→@Slf4j
 31→@ApplicationScoped
 32→public class Tm002EmpVacationService {
 33→
 34→    @Inject
 35→    @PersistenceUnit("eap")
 36→    EntityManager em;
 37→
 38→    /**
 39→     * 執行預設 — 查詢病假設定資料
 40→     * 業務規則 B3：僅回傳病假 1 筆（有效且日期在範圍內）
 41→     */
 42→    public List<Map<String, Object>> getDefaultVacation() {
 43→        String sql = """
 44→                SELECT A.VACATION_CODE, A.VACATION_NAME,
 45→                       B.VACATION_SUB_CODE, B.VACATION_SUB_NAME,
 46→                       B.VACATION_SUB_ID,
 47→                       B.MIN_HOURS, B.MAX_HOURS
 48→                  FROM EAP.TM_VACATION_SETTING A
 49→                  JOIN EAP.TM_VACATION_DETAIL_SETTING B
 50→                    ON A.VACATION_CODE = B.VACATION_CODE
 51→                 WHERE A.VACATION_NAME = NCHAR(30149) + NCHAR(20551)
 52→                   AND GETDATE() BETWEEN B.BEGIN_DATE
 53→                       AND ISNULL(B.END_DATE, CAST('2099-12-31' AS DATE))
 54→                   AND B.IS_EFFECTIVE = 1
 55→                """;
 56→
 57→        // 病 = U+75C5 = 30149, 假 = U+5047 = 20551
 58→        // Use NCHAR() to avoid encoding issues with Chinese characters
 59→        Query query = em.createNativeQuery(sql);
 60→        @SuppressWarnings("unchecked")
 61→        List<Object[]> rows = query.getResultList();
 62→
 63→        List<Map<String, Object>> result = new ArrayList<>();
 64→        for (Object[] row : rows) {
 65→            Map<String, Object> record = new HashMap<>();
 66→            record.put("vacationCode", row[0]);
 67→            record.put("vacationName", row[1]);
 68→            record.put("vacationSubCode", row[2]);
 69→            record.put("vacationSubName", row[3]);
 70→            record.put("vacationSubId", row[4]);
 71→            record.put("minHours", row[5]);
 72→            record.put("maxHours", row[6]);
 73→            result.add(record);
 74→        }
 75→        return result;
 76→    }
 77→
 78→    /**
 79→     * 查詢員工假別明細
 80→     */
 81→    public List<Map<String, Object>> queryEmpVacationDetail(Integer empId, int year) {
 82→        String sql = """
 83→                SELECT
 84→                    v.EMP_VACATION_ID,
 85→                    v.EMP_ID,
 86→                    v.VACATION_SUB_ID,
 87→                    vds.VACATION_CODE,
 88→                    vs.VACATION_NAME,
 89→                    vds.VACATION_SUB_CODE,
 90→                    vds.VACATION_SUB_NAME,
 91→                    v.MAX_HOURS,
 92→                    v.USED_HOURS,
 93→                    v.UNUSED_HOURS,
 94→                    v.CASH_OUT_HOURS,
 95→                    v.BEGIN_DATE,
 96→                    v.END_DATE,
 97→                    v.CLEAR
 98→                FROM EAP.TM_EMP_VACATION v
 99→                INNER JOIN EAP.TM_VACATION_DETAIL_SETTING vds
100→                    ON vds.VACATION_SUB_ID = v.VACATION_SUB_ID
101→                INNER JOIN EAP.TM_VACATION_SETTING vs
102→                    ON vs.VACATION_CODE = vds.VACATION_CODE
103→                WHERE v.EMP_ID = :empId
104→                  AND YEAR(v.BEGIN_DATE) = :year
105→                ORDER BY v.VACATION_SUB_ID
106→                """;
107→
108→        Query query = em.createNativeQuery(sql);
109→        query.setParameter("empId", empId);
110→        query.setParameter("year", year);
111→
112→        @SuppressWarnings("unchecked")
113→        List<Object[]> rows = query.getResultList();
114→
115→        List<Map<String, Object>> result = new ArrayList<>();
116→        for (Object[] row : rows) {
117→            Map<String, Object> record = new HashMap<>();
118→            record.put("empVacationId", row[0]);
119→            record.put("empId", row[1]);
120→            record.put("vacationSubId", row[2]);
121→            record.put("vacationCode", row[3]);
122→            record.put("vacationName", row[4]);
123→            record.put("vacationSubCode", row[5]);
124→            record.put("vacationSubName", row[6]);
125→
126→            BigDecimal maxHours = toBigDecimal(row[7]);
127→            BigDecimal usedHours = toBigDecimal(row[8]);
128→            BigDecimal unusedHours = toBigDecimal(row[9]);
129→
130→            record.put("maxHours", maxHours);
131→            record.put("totalHours", maxHours);
132→            record.put("usedHours", usedHours);
133→            record.put("unusedHours", unusedHours);
134→            record.put("remainingHours", unusedHours);
135→            record.put("cashOutHours", row[10]);
136→            record.put("beginDate", formatDate(row[11]));
137→            record.put("endDate", formatDate(row[12]));
138→
139→            // CLEAR 欄位 — 結算狀態
140→            Object clearVal = row[13];
141→            boolean isClear = false;
142→            if (clearVal != null) {
143→                if (clearVal instanceof Boolean) {
144→                    isClear = (Boolean) clearVal;
145→                } else if (clearVal instanceof Number) {
146→                    isClear = ((Number) clearVal).intValue() == 1;
147→                }
148→            }
149→            record.put("clear", isClear);
150→            record.put("settlementStatus", isClear ? "Y" : "");
151→
152→            result.add(record);
153→        }
154→        return result;
155→    }
156→
157→    /**
158→     * 儲存員工假別明細（新增 + 修改）
159→     * 業務規則 B1：UNUSED_HOURS = MAX_HOURS - USED_HOURS
160→     * 業務規則 B5：不修改 CLEAR 欄位
161→     */
162→    @Transactional
163→    @SuppressWarnings("unchecked")
164→    public List<Map<String, Object>> saveEmpVacationDetails(Integer empId, List<Map<String, Object>> details) {
165→        // 驗證員工存在
166→        String checkSql = "SELECT COUNT(*) FROM EAP.PM_EMPLOYEE WHERE EMP_ID = :empId";
167→        Query checkQuery = em.createNativeQuery(checkSql);
168→        checkQuery.setParameter("empId", empId);
169→        Number count = (Number) checkQuery.getSingleResult();
170→        if (count.intValue() == 0) {
171→            throw new BusinessException("EMP_NOT_FOUND", 400, "員工不存在：" + empId);
172→        }
173→
174→        List<Map<String, Object>> savedRecords = new ArrayList<>();
175→
176→        for (Map<String, Object> detail : details) {
177→            Object empVacationIdObj = detail.get("empVacationId");
178→            Integer vacationSubId = ((Number) detail.get("vacationSubId")).intValue();
179→            BigDecimal maxHours = toBigDecimal(detail.get("maxHours"));
180→            BigDecimal usedHours = toBigDecimal(detail.get("usedHours"));
181→            if (usedHours == null) usedHours = BigDecimal.ZERO;
182→
183→            // B1: 自動計算 UNUSED_HOURS
184→            BigDecimal unusedHours = maxHours.subtract(usedHours);
185→
186→            String beginDateStr = detail.get("beginDate").toString();
187→            String endDateStr = detail.get("endDate").toString();
