260→    /**
261→     * 批次驗證員工
262→     * 業務規則 B10：
263→     * - 在職 → 有效
264→     * - 已離職 → 「員工已離職」
265→     * - 查不到 → 「查無此員工」
266→     */
267→    public List<Map<String, Object>> validateEmployees(List<String> empAccounts) {
268→        List<Map<String, Object>> results = new ArrayList<>();
269→
270→        for (String empAccount : empAccounts) {
271→            Map<String, Object> result = new HashMap<>();
272→            result.put("empAccount", empAccount);
273→
274→            String sql = """
275→                    SELECT e.EMP_ID, e.EMP_NAME, e.ORG_ID, e.LEAVE_DATE,
276→                           org.ORG_NAME
277→                    FROM EAP.PM_EMPLOYEE e
278→                    LEFT JOIN EAP.AU_ORGANIZATION org ON org.ORG_ID = e.ORG_ID
279→                    WHERE e.EMP_ACCOUNT = :empAccount
280→                    """;
281→            Query query = em.createNativeQuery(sql);
282→            query.setParameter("empAccount", empAccount);
283→
284→            @SuppressWarnings("unchecked")
285→            List<Object[]> rows = query.getResultList();
286→
287→            if (rows.isEmpty()) {
288→                result.put("valid", false);
289→                result.put("errorMessage", "查無此員工");
290→            } else {
291→                Object[] row = rows.get(0);
292→                Object leaveDate = row[3];
293→                boolean isResigned = leaveDate != null;
294→
295→                if (isResigned) {
296→                    result.put("valid", false);
297→                    result.put("errorMessage", "員工已離職");
298→                } else {
299→                    result.put("valid", true);
300→                    result.put("empId", row[0]);
301→                    result.put("empName", row[1]);
302→                    result.put("orgId", row[2]);
303→                    result.put("orgName", row[4]);
304→                }
305→            }
306→
307→            results.add(result);
308→        }
309→
310→        return results;
311→    }
312→
313→    /**
314→     * 批次匯入建立
315→     * 業務規則 B1：UNUSED_HOURS = MAX_HOURS - 0（新建已用為 0）
316→     * 業務規則 B11：結束日不可早於起始日
317→     */
318→    @Transactional
319→    @SuppressWarnings("unchecked")
320→    public int batchImport(Map<String, Object> payload) {
321→        // 驗證必填
322→        Object empIdsObj = payload.get("empIds");
323→        Object vacSubIdObj = payload.get("vacationSubId");
324→        Object maxHoursObj = payload.get("maxHours");
325→        Object beginDateObj = payload.get("beginDate");
326→        Object endDateObj = payload.get("endDate");
327→
328→        if (empIdsObj == null || !(empIdsObj instanceof List) || ((List<?>) empIdsObj).isEmpty()) {
329→            throw new BusinessException("REQUIRED_FIELD", 400, "empIds 為必填欄位");
330→        }
331→        if (vacSubIdObj == null) {
332→            throw new BusinessException("REQUIRED_FIELD", 400, "vacationSubId 為必填欄位");
333→        }
334→        if (maxHoursObj == null) {
335→            throw new BusinessException("REQUIRED_FIELD", 400, "maxHours 為必填欄位");
336→        }
337→        if (beginDateObj == null) {
338→            throw new BusinessException("REQUIRED_FIELD", 400, "beginDate 為必填欄位");
339→        }
340→        if (endDateObj == null) {
341→            throw new BusinessException("REQUIRED_FIELD", 400, "endDate 為必填欄位");
342→        }
343→
344→        List<Number> empIds = (List<Number>) empIdsObj;
345→        Integer vacationSubId = ((Number) vacSubIdObj).intValue();
346→        BigDecimal maxHours = toBigDecimal(maxHoursObj);
347→        LocalDate beginDate = LocalDate.parse(beginDateObj.toString());
348→        LocalDate endDate = LocalDate.parse(endDateObj.toString());
349→
350→        // B11: 結束日不可早於起始日
351→        if (endDate.isBefore(beginDate)) {
352→            throw new BusinessException("DATE_INVALID", 400, "結束日不可早於起始日");
353→        }
354→
355→        // 驗證假別細項存在
356→        String checkSql = "SELECT COUNT(*) FROM EAP.TM_VACATION_DETAIL_SETTING WHERE VACATION_SUB_ID = :vacSubId";
357→        Query checkQuery = em.createNativeQuery(checkSql);
358→        checkQuery.setParameter("vacSubId", vacationSubId);
359→        Number checkCount = (Number) checkQuery.getSingleResult();
360→        if (checkCount.intValue() == 0) {
361→            throw new BusinessException("VAC_SUB_NOT_FOUND", 400, "假別細項不存在：" + vacationSubId);
362→        }
363→
364→        // B1: UNUSED = MAX - 0
365→        BigDecimal unusedHours = maxHours;
366→
367→        int createdCount = 0;
368→        for (Number empIdNum : empIds) {
369→            Integer empId = empIdNum.intValue();
370→
371→            TmEmpVacationEntity entity = new TmEmpVacationEntity();
372→            entity.empId = empId;
373→            entity.vacationSubId = vacationSubId;
374→            entity.maxHours = maxHours;
375→            entity.usedHours = BigDecimal.ZERO;
376→            entity.unusedHours = unusedHours;
377→            entity.cashOutHours = BigDecimal.ZERO;
378→            entity.beginDate = beginDate;
379→            entity.endDate = endDate;
380→            entity.clear = false;
381→            entity.persist();
382→            createdCount++;
383→        }
384→
385→        em.flush();
386→        return createdCount;
387→    }
388→
389→    // ==================== 私有輔助方法 ====================
390→
391→    private BigDecimal toBigDecimal(Object obj) {
392→        if (obj == null) return null;
393→        if (obj instanceof BigDecimal) return (BigDecimal) obj;
394→        if (obj instanceof Number) return BigDecimal.valueOf(((Number) obj).doubleValue());
395→        try {
396→            return new BigDecimal(obj.toString().trim());
397→        } catch (NumberFormatException e) {
398→            return null;
399→        }
400→    }
401→
402→    private String formatDate(Object dateObj) {
403→        if (dateObj == null) return null;
404→        if (dateObj instanceof java.sql.Date sqlDate) {
405→            return DateFormatUtil.formatDate(sqlDate.toLocalDate());
406→        }
407→        if (dateObj instanceof java.sql.Timestamp timestamp) {
408→            return DateFormatUtil.formatDate(timestamp.toLocalDateTime().toLocalDate());
409→        }
410→        if (dateObj instanceof LocalDateTime localDateTime) {
411→            return DateFormatUtil.formatDate(localDateTime.toLocalDate());
412→        }
413→        if (dateObj instanceof LocalDate localDate) {
414→            return DateFormatUtil.formatDate(localDate);
415→        }
416→        String str = dateObj.toString();
417→        if (str.length() >= 10) {
418→            return str.substring(0, 10);
419→        }
420→        return str;
421→    }
422→}
