21→/**
22→ * TM002 員工假別明細刪除 Processor
23→ * <p>
24→ * 刪除員工假別額度明細（硬刪除）
25→ * 結算列（CLEAR=1）不可刪除
26→ * API 路徑：POST /api/tm002EmpVacationDelete
27→ *
28→ * @author SoeTek Team
29→ * @since 2026-03-26
30→ */
31→@Slf4j
32→@ApplicationScoped
33→@Named("tm002EmpVacationDeleteProcessor")
34→@RegisterForReflection
35→public class Tm002EmpVacationDeleteProcessor extends ApiRouteProcessor {
36→
37→    @Inject
38→    Tm002EmpVacationService empVacationService;
39→
40→    @Override
41→    public Map<String, Object> getTemplateParams() {
42→        return Map.of(
43→                "routeId", "tm002EmpVacationDelete",
44→                "apiDescription", "刪除員工假別明細",
45→                "requiredFields", "empVacationId");
46→    }
47→
48→    @Override
49→    protected String getProcessorType() {
50→        return LogType.API_PROCESSING;
51→    }
52→
53→    @Override
54→    @ActivateRequestContext
55→    @AuditLog(
56→            operation = AuditLog.OperationType.DELETE,
57→            entity = "TmEmpVacation",
58→            description = "刪除員工假別明細",
59→            logParameters = true,
60→            logResult = false
61→    )
62→    public Object process(Exchange exchange, @Body Map<String, Object> payload,
63→                          @Headers Map<String, Object> headers) throws Exception {
64→        return executeWithErrorHandling(exchange, payload, headers);
65→    }
66→
67→    @Override
68→    protected Object processBusinessLogic(
69→            Exchange exchange,
70→            Map<String, Object> payload,
71→            Map<String, Object> headers,
72→            String traceId,
73→            String routeId) throws Exception {
74→
75→        Object idObj = payload.get("empVacationId");
76→        if (idObj == null) {
77→            throw new BusinessException("REQUIRED_FIELD", 400, "empVacationId 為必填欄位");
78→        }
79→        Integer empVacationId = ((Number) idObj).intValue();
80→
81→        log.debug("[TM002 刪除] empVacationId: {}, TraceId: {}", empVacationId, traceId);
82→
83→        empVacationService.deleteEmpVacation(empVacationId);
84→
85→        log.info("[TM002 刪除] 完成 - empVacationId: {}, TraceId: {}", empVacationId, traceId);
86→
87→        Map<String, Object> data = new HashMap<>();
88→        data.put("empVacationId", empVacationId);
89→        data.put("entityId", empVacationId);
90→
91→        return buildStandardResponse(traceId, data);
92→    }
93→}
