  1→/**
  2→ * TM002 員工年度假別額度維護 - Store
  3→ *
  4→ * @author SoeTek Team
  5→ * @since 2026-03-26
  6→ */
  7→
  8→import { defineStore } from 'pinia'
  9→import { ref, computed } from 'vue'
 10→import { tm002Service } from 'src/services/tm/tm002Service'
 11→import { useErrorHandler } from 'src/composables/useErrorHandler'
 12→import type {
 13→  IEmpVacationListItem,
 14→  IEmpVacationQueryParams,
 15→  IEmpVacationDetail,
 16→  IDefaultVacationItem,
 17→  IEmployeeInfo,
 18→  IBatchValidateResult,
 19→  IEmpVacationSaveParams,
 20→  IBatchImportParams
 21→} from 'src/types/tm/tm002'
 22→
 23→export const useTm002Store = defineStore('tm002', () => {
 24→
 25→  const { showError } = useErrorHandler()
 26→
 27→  // ==================== State ====================
 28→
 29→  const records = ref<IEmpVacationListItem[]>([])
 30→  const totalCount = ref(0)
 31→  const currentPage = ref(1)
 32→  const queryLoading = ref(false)
 33→  const saveLoading = ref(false)
 34→  const deleteLoading = ref(false)
 35→
 36→  // Dialog state
 37→  const detailRecords = ref<IEmpVacationDetail[]>([])
 38→  const defaultVacationItems = ref<IDefaultVacationItem[]>([])
 39→  const employeeInfo = ref<IEmployeeInfo | null>(null)
 40→  const batchValidateResults = ref<IBatchValidateResult[]>([])
 41→
 42→  // ==================== Getters ====================
 43→
 44→  const hasData = computed(() => records.value.length > 0)
 45→  const isAnyLoading = computed(() =>
 46→    queryLoading.value || saveLoading.value || deleteLoading.value
 47→  )
 48→
 49→  // ==================== Actions ====================
 50→
 51→  /** 清單查詢 */
 52→  async function query(params?: IEmpVacationQueryParams): Promise<boolean> {
 53→    queryLoading.value = true
 54→    try {
 55→      const response = await tm002Service.query(params)
 56→      if (response.success && response.data) {
 57→        records.value = response.data.records || []
 58→        totalCount.value = response.data.totalCount || 0
 59→        currentPage.value = response.data.currentPage || 1
 60→        return true
 61→      }
 62→      return false
 63→    } catch (err: unknown) {
 64→      showError(err)
 65→      return false
 66→    } finally {
 67→      queryLoading.value = false
 68→    }
 69→  }
 70→
 71→  /** 員工資訊查詢 */
 72→  async function queryEmpInfo(empAccount: string): Promise<IEmployeeInfo | null> {
 73→    try {
 74→      const response = await tm002Service.queryEmpInfo(empAccount)
 75→      if (response.success && response.data) {
 76→        employeeInfo.value = response.data
 77→        return response.data
 78→      }
 79→      return null
 80→    } catch (err: unknown) {
 81→      showError(err)
 82→      return null
 83→    }
 84→  }
 85→
 86→  /** 執行預設（病假載入） */
 87→  async function loadDefaultVacation(year: number): Promise<boolean> {
 88→    try {
 89→      const response = await tm002Service.getDefaultVacation(year)
 90→      if (response.success && response.data) {
 91→        defaultVacationItems.value = response.data.records || []
 92→        return true
 93→      }
 94→      return false
 95→    } catch (err: unknown) {
 96→      showError(err)
 97→      return false
 98→    }
 99→  }
100→
101→  /** 明細查詢 */
102→  async function queryDetail(empId: number, year: number): Promise<boolean> {
103→    queryLoading.value = true
104→    try {
105→      const response = await tm002Service.queryDetail(empId, year)
106→      if (response.success && response.data) {
107→        detailRecords.value = response.data.records || []
108→        return true
109→      }
110→      return false
111→    } catch (err: unknown) {
112→      showError(err)
113→      return false
114→    } finally {
115→      queryLoading.value = false
116→    }
117→  }
118→
119→  /** 儲存明細 */
120→  async function saveDetails(params: IEmpVacationSaveParams): Promise<boolean> {
121→    saveLoading.value = true
122→    try {
123→      const response = await tm002Service.save(params)
124→      if (response.success) {
125→        return true
126→      }
127→      return false
128→    } catch (err: unknown) {
129→      showError(err)
130→      throw err
131→    } finally {
132→      saveLoading.value = false
133→    }
134→  }
135→
136→  /** 刪除明細 */
137→  async function deleteDetail(empVacationId: number): Promise<boolean> {
138→    deleteLoading.value = true
139→    try {
140→      const response = await tm002Service.deleteDetail(empVacationId)
141→      if (response.success) {
142→        return true
143→      }
144→      return false
145→    } catch (err: unknown) {
146→      showError(err)
147→      throw err
148→    } finally {
149→      deleteLoading.value = false
150→    }
151→  }
152→
153→  /** 批次驗證 */
154→  async function batchValidate(empAccounts: string[]): Promise<boolean> {
155→    try {
156→      const response = await tm002Service.batchValidate(empAccounts)
157→      if (response.success && response.data) {
158→        batchValidateResults.value = response.data.results || []
159→        return true
160→      }
161→      return false
162→    } catch (err: unknown) {
163→      showError(err)
164→      return false
165→    }
166→  }
167→
168→  /** 批次匯入 */
169→  async function batchImport(params: IBatchImportParams): Promise<number> {
170→    saveLoading.value = true
171→    try {
172→      const response = await tm002Service.batchImport(params)
173→      if (response.success && response.data) {
174→        return response.data.createdCount
175→      }
176→      return 0
177→    } catch (err: unknown) {
178→      showError(err)
179→      throw err
180→    } finally {
181→      saveLoading.value = false
182→    }
183→  }
184→
185→  /** 重置 */
186→  function $reset() {
187→    records.value = []
188→    totalCount.value = 0
189→    currentPage.value = 1
190→    queryLoading.value = false
191→    saveLoading.value = false
192→    deleteLoading.value = false
193→    detailRecords.value = []
194→    defaultVacationItems.value = []
195→    employeeInfo.value = null
196→    batchValidateResults.value = []
197→  }
198→
199→  // ==================== Return ====================
200→
201→  return {
202→    // State
203→    records, totalCount, currentPage,
204→    queryLoading, saveLoading, deleteLoading,
205→    detailRecords, defaultVacationItems, employeeInfo, batchValidateResults,
206→    // Getters
207→    hasData, isAnyLoading,
208→    // Actions
209→    query, queryEmpInfo, loadDefaultVacation, queryDetail,
210→    saveDetails, deleteDetail, batchValidate, batchImport, $reset
211→  }
212→})
